INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('230e3d72-74bf-5414-bbaa-06a1b6db4a90','NOW - Vitamin C-500 RH / 100 tabs','00261','<p>Витамин С &#8211; это водорастворимое питательное вещество, хорошо известное своей жизненно важной ролью в функционировании иммунной системы.</p>',true,95804,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('af518860-d8a9-529e-947a-dd954b84b292','Now - Витамин С-1000мг, 100капс','00301','<p>Водорастворимый витамин C играет важную роль в поддержании нормального функционирования иммунной системы.</p>',true,95803,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('f898d408-2bee-5f5d-a7aa-c4200ba1d55e','Now - Витамин B-6 100мг,100капс','00087','<p>Витамин B-6 является кофактором во многих ферментных реакциях, а также необходим для обмена жиров, белков и углеводов.</p>',true,95802,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('a351ce91-b58f-5b1f-9e5f-b97877d082ee','NOW Vitamin B-2 капс ., 100мг, 100 шт.','00147','<p>Данное вещество активно участвует в окислительно-восстановительных реакциях, отвечает за углеводный, белковый и липидный обмен.</p>',true,95801,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('0c6ce55f-d69f-502a-8f9e-298f1147a746','NOW Ultra A&D-3, 100 шт.','00202','<p>Ультра витамины A и D-3 помогают поддерживать крепкие кости и зубы и необходимы для поддержания здоровья глаз.</p>',true,95800,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('79d7f123-04ae-569c-8b85-d955de9e111a','NOW Tri-Amino, нейтральный, 120 шт.','00131','<p>NOW Foods Tri-Amino / Три-Амино 120 капсул</p>',true,95799,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('dc427eb6-3dbd-59f5-98f7-eb5c59a77620','NOW - Super omega EPA 1200мг 120 шт.','00283','<p>NOW Super Омега-3 &#8211; натуральный концентрат рыбьего жира производится в соответствии со строгими стандартами контроля качества.</p>',true,95798,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('4a898b20-ef72-530c-97b4-bc39dd0a543b','NOW Selenium 200мкг, 90шт.','00236','<p>Минерал, который можно получить из препарата NOW Selenium, обладает мощным иммуностимулирующим, детоксикационным, а также противоопухолевым эффектом.</p>',true,95797,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('afdd6ea7-622b-5f08-b17a-796437e4cf69','NOW Potassium Plus Iodine, 180 шт.','00281','<p>Йодид калия (KI) &#8211; это соединение, содержащее йод, питательное вещество, необходимое для нормальной работы щитовидной железы.</p>',true,95795,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('2cd018b3-e15d-5efb-bd7a-be0869fb3f43','NOW Propolis 1500 (5:1 Extract), 100 шт.','00228','<p>Добавка Propolis производства компании Now Foods содержит натуральный прополис (пчелиный клей), который оказывает на организм выраженное антибактериальное и иммуностимулирующее действие</p>',true,95796,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('ca96141a-f88c-559d-8545-14c36d316e8a','NOW - PABA, 500 мг, 100 шт.','00284','<p>ПАБК (пара-аминобензойная кислота) содержится в таких продуктах питания, как зерновые, яйца, молоко и мясо. Она является прекурсором фолиевой кислоты.</p>',true,95794,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('525c845e-6256-53d5-a719-c7f5a94e8bef','NOW - Метилсульфонилметан 1000 мг - 120 капсул','00122','<p>MSM 1000 – эффективный препарат, содержащий в своем составе органическую серу, количество которой в организме человека должно ежедневно восполняться посредством определенных продуктов питания.</p>',true,95793,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('da0877d2-7c7d-5202-baeb-bab1cccf305a','NOW - Mака / 500мг / 100капс','00244','<p>Мака является природным афродизиаком, стимулирует половую функцию, усиливает половое влечение у женщин и мужчин.</p>',true,95792,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('9c6825de-b356-53b6-8183-0e232b1ce126','NOW - L-Глютамин / 500мг / 120капс','00222','<p>L-Глютамин является важным компонентом для организма человека, который помогает восстанавливаться от нагрузок, поддерживает иммунитет и мышечную массу.</p>',true,95791,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('36c2e267-9541-5e2b-a0fa-743199a94f31','NOW Kids - Kid Vits Beryy Blast / 120 таб. жев.','00233','<p>Kid Vits – это детские витамины производства всемирно известной компании NOW Foods (США). Kid Vits созданы с учетом особенностей детского организма, все ингредиенты подобраны именно в тех дозировках, которые необходимы для нормального развития ребенка.</p>',true,95790,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('eb63d58a-304b-584d-a26b-e315f0737c78','NOW Kids - Kid Cal / 100таб. жев.','00314','<p>Комплекс витаминов для детей Kid Cal обеспечат здоровье, рост и формирование костной ткани у детей.</p>',true,95789,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('09eded68-49c0-534f-9caf-c4327e2ccc98','NOW - Kelp Powder / 8 oz / 227гр','00214','<div>Препарат из ламинарий компании Now Foods обеспечивает естественный профиль питательных веществ, содержащихся в натуральной цельной пище.</div>
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('93bbe909-26d7-51d9-a847-fcc46530f34d','NOW - Комплекс Железо  / 100таб','00063','<p>NOW Iron Complex &#8211; это уникальная смесь железа и его важных сопутствующих питательных веществ в сочетании с дополнительными растительными компонентами. Железо &#8211; это минерал, необходимый для образования гемоглобина, молекулы, которая транспортирует кислород к клеткам по всему телу в красных кровяных тельцах.</p>',true,95787,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('cd9b65f9-0a6c-58df-a924-2bdd04e39369','NOW - Глюкозамин и МСМ / 60капс','00269','<p>Глюкозамин – это аминосахар, полученный из хитина раковин. Глюкозамин и МСМ комбинируют пищевые преимущества двух мощных пищевых добавок.</p>
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('dceec91e-5de9-5685-8872-f3938d8e5fe0','NOW - Eve Women''s Multi / 90капс','00302','<p>EVE Superior Womens Multi &#8211; это комплекс витаминов и минералов специально разработанный для женского организма. Способствует восстановлению баланса гормонов, облегчает симптомы климактерического характера, препятствуют возникновению остеопороза, укрепляют ломкие ногти, улучшает состояние волос и кожи, а также общее самочувствие.</p>',true,95785,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('71985091-df09-58e4-928c-87ffa21b493a','NOW - Evening Primrose / 500мг / 100капс','00282','<p>Полиненасыщенные жирные кислоты играют большую роль в поддержании здоровья человеческого организма. Соединения входят в состав клеточных мембран, помогают в транспортировки липидов и поддерживают здоровье сердечно-сосудистой системы.</p>',true,95784,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('8787eb58-2f2d-5e9c-9662-d4c197614a37','NOW - CoQ 10 / 30мг / 60капс','00275','<p>Кофермент Q10 (CoQ10) представляет собой витаминоподобное сложное вещество, которое играет центральную роль в выработке клеточной энергии.</p>',true,95783,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('9c19b6d4-4b38-5186-85db-30e8a11fc2cb','NOW - CLA / 800мг / 90капс','00106','<p>КЛК (конъюгированная линолевая кислота) — это класс жирных кислот, вырабатываемых животными, которые естественным образом содержатся в говядине и молочных продуктах.</p>',true,95782,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('a441b90a-8176-5926-a47e-4f97008ab6f1','NOW - Calcium & Magnesium & D3 and Zinc / 120капс','00227','<p>Минеральный комплекс содержит кальций и магний в оптимальных пропорциях и дополнительно обогащен витамином D и цинком. Все вещества, входящие в состав этой пищевой добавки дополняют активные свойства друг друга и воздействуют на организм синергично.</p>
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('f2cbc011-2474-5b4f-9302-2d6c08566c45','NOW American Ginseng, 500мг, 100шт.','00255','<p>Американский женьшень (Panax quinquefolius) используется традиционными травниками на протяжении веков. Данные недавних научных исследований подтверждают наличие в американском женьшене биологически активных соединений, известных как гинзенозиды, которые придают этому растению адаптогенные свойства.</p>',true,95779,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('f2b37e62-b4e8-55e8-bd8b-5dacd0714cd3','NOW - Calcium & Magnesium / 500мг & 250мг / 100тб','00050','<p>Макроэлементы «Кальций Магний» являются очень важными компонентами, необходимыми для функционирования организма. Они требуются каждому человеку для поддержания здоровья и хорошего самочувствия.</p>',true,95780,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('790e88a7-26eb-5127-b80f-ccfadfa76583','Now ADAM MALE MULTI, 90 капсула','00206','<p>Витамины для мужчин NOW ADAM (АДАМ) содержат высокий уровень необходимых биологических компонентов в большой концентрации и, тем самым, обеспечивают максимальный уровень потребления основных минералов, жирных кислот и активных растительных веществ и витаминов, важных для обеспечения мужского здоровья и органов половой системы.</p>',true,95778,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('348dac93-ff04-5ef6-a70f-501c9ad0b4a1','MST - Комплекс  Витамин  B300 100 таб','00020','<p>MST® B300 vitamin complex 100 таблеток представляет собой полный комплекс витаминов группы В, являющихся составной частью энзимов, регулирующих метаболизм углеводов, жиров и белков в организме.</p>',true,95777,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('bd195527-5227-509a-82f6-e12b25d75a65','NOW - Омега-3 капсулы 1000мг №200','00207','<p>Омега-3 – жирные кислоты оказались особенно эффективны для снижения уровня атерогенных триглицеридов в крови, а также “плохого” холестерина – липопротеидов низкой плотности.</p>',true,95776,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('648648c5-2c2f-5e8f-86e1-25417ac0e96e','NOW - Омега-3 капсулы 1000мг №100','00310','<p>Омега-3 – жирные кислоты оказались особенно эффективны для снижения уровня атерогенных триглицеридов в крови, а также “плохого” холестерина – липопротеидов низкой плотности.</p>',true,95775,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('5d322183-9242-5def-b68a-f376c2a619df','Now - Витамин B-Комплекс таблетки 100мг №100','00317','<p>Таблетки содержат полный набор витаминов группы B, а также холин и инозитол.</p>',true,95773,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('b10b8829-225f-5ce7-8d4d-99153517a7c3','NOW - Витамин E капсулы E-200 №100','00321','<p>Витамин Е выполняет в организме важную защитную функцию, предотвращая разрушающее действие свободных радикалов, главной мишенью которых являются ненасыщенные углеродные связи жирных кислот.</p>',true,95774,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
