INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('44324c0f-09d5-578b-9e3c-c7d7a505fb12','NOW - Мелатонин капсулы 10мг №100','00021','<p>Мелатонин — это эффективный нейтрализатор свободных радикалов, который естественно вырабатывается шишковидной железой и присутствует в большом количестве в желудочно- кишечном тракте.</p>',true,95770,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('571afca0-ba88-5f74-ac6b-a6f8eeec6ea9','NOW - Железо капсулы 36мг №90','00262','<p>Железо — это важный минерал, играющий центральную роль в процессах выработки энергии, работы иммунной и нервной систем. Железо — это важнейший компонент гемоглобина, молекулы, переносящей кислород к клеткам тела.</p>',true,95769,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
