INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('9deb5c04-22b0-5107-aee8-47a691b47100','Аквалор беби капли 15мл','1-008608','<p>Средство для промывания полости носа для детей «Аквалор беби» 15 мл представляет собой пластиковый флакон-капельницу, герметично закрытый завинчивающейся пластиковой крышкой. Содержание флакона-капельницы — прозрачная бесцветная жидкость без запаха, со слабосоленым вкусом, являющаяся стерильным раствором морской воды с изотонической концентрацией NaCl.</p>',true,60094,'967785bb-3abe-5ccc-ba6f-a63a335411f4');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('977945ff-a97d-524a-8997-51113f08b471','Трибестан тб 250мг №60','1-008612','<p>Трибестан — препарат растительного происхождения, получаемый по оригинальной технологии из надземной части растения якорцы стелющиеся (Tribulus terrestris L.), содержит преимущественно стероидные сапонины фуростанолового типа.</p>',true,60098,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
