INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('009d4841-c179-5d4c-a1f5-f7c999b34128','Витапрост-Форте супп. рект. №10','1-008554','<p>Витапрост® Форте обладает органотропным действием в отношении предстательной железы.</p>',true,60040,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('76ac994f-f408-5347-8516-304edf44bb03','Витапрост тб 20мг №20','1-008556','<p>Витапрост обладает органотропным действием в отношении предстательной железы. Уменьшает степень отека, лейкоцитарной инфильтрации предстательной железы, нормализует секреторную функцию эпителиальных клеток, увеличивает число лецитиновых зерен в секрете ацинусов, стимулирует мышечный тонус мочевого пузыря. </p>',true,60042,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('16391be7-2ac5-5652-9a33-304d591a6791','Витапрост супп. рект. №10','1-008558','<p>К применению препарата — острый и хронический бактериальный простатит, вызванный чувствительными микроорганизмами, (в т.ч. сопровождающийся воспалительными заболеваниями мочеполового тракта.</p>',true,60044,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('2eaebf2c-caf9-5521-baa4-d08f54b152ff','Витапрост Плюс супп. рект. №10','1-008560','<p>К применению препарата — острый и хронический бактериальный простатит, вызванный чувствительными микроорганизмами, (в т.ч. сопровождающийся воспалительными заболеваниями мочеполового тракта.</p>',true,60046,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
