INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('a013f0d8-ffc1-52d9-a0eb-309e11f836f2','Вовенак мазь 1% 20г','1-006908','<p>Диклофенак диэтиламии сдерживает биосинтез простагландина; облегчает боль, уменьшает отек и воспаление травматического или артритического характера.</p>',true,58394,'b3d64380-8e6e-555b-a24c-78b5c334cb63');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('2478f191-989e-5dc4-b418-d151b301362f','Коликвел капли 15мл','1-006890','<p>Ретинол (витамин А) оказывает общеукрепляющее действие, нормализует тканевой обмен, является мощным антиоксидантом, участвует в окислительно-восстановительных процессах, регуляции синтеза белков, липидов, мукополисахаридов, в минеральном обмене, процессах образования холестерина.</p>',true,58376,'d538ca47-212d-5368-8878-84883860f986');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('a4be3ba4-ae34-59e6-82e3-b6debfb69a60','Менстан крем 20г (клотримазол)','1-006874','<p>Клотримазол является синтетическим производным имидазола. Он применяется главным образом местно при лечении кожных и вагинальных инфекций, вызванных дрожжевыми грибами и дерматофитами.</p>',true,58360,'8c3ee89b-6301-54b8-ab9f-6d85f61dd47c');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('9236e58c-9002-520f-91e6-4f5e1d63fa43','Лоркоф сироп 100мл','1-006878','<p>Оказывает выраженный бронхолитический эффект, предупреждает и купирует бронхоспазм, снижает сопротивление в дыхательных путях, увеличивает жизненную емкость легких. </p>',true,58364,'747d2ffc-cf89-55af-9933-3bd6be3d0f7a');
INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('6d66b184-532b-5c9f-814b-7c8cb8d378c3','Кука сироп от кашля 100мл','1-006885','<p>КУКА сироп от кашля &#8211; комбинированный препарат из компонентов растительного происхождения, применяемый при простудных заболеваниях и кашле.</p>',true,58371,'747d2ffc-cf89-55af-9933-3bd6be3d0f7a');
