INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('2e45a79b-0f47-5de0-905b-ed327b9910ac','Почкам сироп 100мл','1-006864','<p>Почкам плюс сироп – многокомпонентный препарат растительного происхождения, состоит из комбинации лечебных трав, которые оказывают противовоспалительное, антибактериальное, мочегонное, спазмолитическое действие. </p>',true,58350,'eb9f7e3c-54b7-5d6c-896b-c8db9ae1ec65');
