INSERT INTO medicines (id,title,articul,description,is_active,woo_commerce_id,category_id) VALUES ('b452b88f-b468-58c1-91c6-a099204342e9','Лив-52 тб №100','1-006774','<p>Лив 52 &#8211; комбинированный растительный препарат. Оказывает гепатопротекторное, антитоксическое, противовоспалительное, желчегонное, антиоксидантное, антианорексическое действие.</p>',true,58260,'03e8fc06-4725-560d-afcb-5c8d990d2e22');
